// ============================================

const pgHost = 'shuttle.proxy.rlwy.net';
const pgPort = '56612';
const pgUser = 'postgres';
const pgPass = 'SlhKtARznaTeNCcIYrYBmSPWNtlupkQr';
const pgDb = 'railway';

// Use n8n's built-in HTTP request to call a simple query via the existing Util workflow
// OR fetch directly. For POC, we'll fetch via the n8n postgres approach.
// Since Code nodes can't use postgres directly, we'll use HTTP to our own API.

// Alternative: hardcode the recipes from DB for now, fetch live later
