  let currentGroup = null;

  for (const scene of scenes) {
    const recipe = sceneRecipes[scene.scene_slug];
    const avatarDef = recipe.definition.avatar;
    const avatarVariant = (avatarDef && avatarDef.required)
      ? (avatarDef.default_variant || null)
      : null;

    if (avatarVariant === null) {
      // No avatar in this scene — close current group if open
      if (currentGroup) {
        groups.push(currentGroup);
        currentGroup = null;
      }
      continue;
    }

    if (currentGroup && currentGroup.avatar_variant === avatarVariant) {
      // Same avatar position — extend current group
      currentGroup.scenes.push(scene.scene_slug);
      currentGroup.audio_text += ' ' + scene.audio_text;
    } else {
      // Different avatar or new group — close current, start new
      if (currentGroup) groups.push(currentGroup);
      currentGroup = {
        group_id: 'group_' + groups.length,
        avatar_variant: avatarVariant,
        scenes: [scene.scene_slug],
        audio_text: scene.audio_text,
        start_scene_position: scene.position
      };
    }
  }

  if (currentGroup) groups.push(currentGroup);
  return groups;
}

const avatarGroups = groupAvatarContinuity(scenes, sceneRecipes);

console.log('Avatar continuity groups: ' + avatarGroups.length);
avatarGroups.forEach(g => {
  console.log('  ' + g.group_id + ': ' + g.avatar_variant + ' (scenes: ' + g.scenes.join(', ') + ')');
});

// ============================================
// STEP 4: Return enriched data
// ============================================

return {
  json: {
    ...input,
    scenes: scenes,
    _avatar_groups: avatarGroups,
    _video_recipe: videoRecipe,
    _scene_recipes: sceneRecipes
  }
};

})();

// ============================================
// SLICE AUDIO PER AVATAR GROUP
// Downloads full TTS audio, slices per continuity group
// using ffmpeg, uploads slices to Cloudinary.
// ============================================

return (async () => {

const input = $json;
const avatarGroups = input._avatar_groups || [];
const sceneTimings = input._scene_timings || [];
const fullAudioUrl = input.full_audio_url;

if (!avatarGroups.length) {
  console.log('No avatar groups — skipping audio slicing');
  return { json: input };
}

if (!fullAudioUrl) {
  console.log('No full_audio_url — skipping audio slicing (POC mode)');
  return { json: input };
}

if (!sceneTimings.length) {
  throw new Error('_scene_timings required for audio slicing');
}

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// Download full audio to temp file
const tmpDir = '/tmp/audio_slicing_' + Date.now();
fs.mkdirSync(tmpDir, { recursive: true });
const fullAudioPath = path.join(tmpDir, 'full_audio.mp3');

console.log('Downloading full audio: ' + fullAudioUrl);
execSync('curl -sL -o ' + fullAudioPath + ' "' + fullAudioUrl + '"');

const updatedGroups = [];

for (const group of avatarGroups) {
  // Find timing boundaries for this group's scenes
  const firstSceneTiming = sceneTimings.find(t => t.scene === group.scenes[0]);
  const lastSceneTiming = sceneTimings.find(t => t.scene === group.scenes[group.scenes.length - 1]);

  if (!firstSceneTiming || !lastSceneTiming) {
    console.log('WARNING: Missing timing for group ' + group.group_id + ', skipping');
    updatedGroups.push(group);
    continue;
  }

  const startTime = firstSceneTiming.start;
  const endTime = lastSceneTiming.end;
  const slicePath = path.join(tmpDir, group.group_id + '.mp3');

  console.log('Slicing ' + group.group_id + ': ' + startTime + 's -> ' + endTime + 's (' + (endTime - startTime).toFixed(2) + 's)');

  // ffmpeg slice
  execSync(
    'ffmpeg -y -i ' + fullAudioPath +
    ' -ss ' + startTime +
    ' -to ' + endTime +
    ' -c copy ' + slicePath
  );

  // Verify the slice exists
  if (!fs.existsSync(slicePath)) {
    throw new Error('ffmpeg slice failed for ' + group.group_id);
  }

  const sliceSize = fs.statSync(slicePath).size;
  console.log('  Slice size: ' + (sliceSize / 1024).toFixed(1) + ' KB');

  // Upload to Cloudinary (unsigned)
  const publicId = 'audio-slices/' + group.group_id + '-' + Date.now();
  const uploadResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.cloudinary.com/v1_1/dtpqxuwby/video/upload',
    headers: { 'Content-Type': 'application/json' },
    body: {
      file: 'data:audio/mpeg;base64,' + fs.readFileSync(slicePath).toString('base64'),
      upload_preset: 'n8n_unsigned',
      public_id: publicId,
      resource_type: 'video'
    },
    json: true
  });

  if (uploadResult.error) {
    throw new Error('Cloudinary upload failed for ' + group.group_id + ': ' + uploadResult.error.message);
  }

  console.log('  Uploaded: ' + uploadResult.secure_url);

  updatedGroups.push({
    ...group,
    audio_url: uploadResult.secure_url,
    audio_duration: endTime - startTime
  });
}

// Cleanup temp files
try { execSync('rm -rf ' + tmpDir); } catch (e) {}

console.log('Audio slicing complete. ' + updatedGroups.length + ' groups processed.');

return {
  json: {
    ...input,
    _avatar_groups: updatedGroups
  }
};

})();

// ============================================
// RENDER AVATARS PER GROUP
// For each avatar continuity group:
//   1. Submit HeyGen render with group's sliced audio
//   2. Poll for completion
//   3. Submit Replicate RVM for alpha mask
//   4. Poll for completion
//   5. Store video_url + mask_url on group
// ============================================

return (async () => {

const input = $json;
const avatarGroups = input._avatar_groups || [];

if (!avatarGroups.length) {
  console.log('No avatar groups — skipping HeyGen renders');
