}

// Check if groups have audio URLs (required for HeyGen)
const groupsWithAudio = avatarGroups.filter(g => g.audio_url);
if (!groupsWithAudio.length) {
  console.log('No groups with audio_url — skipping HeyGen renders (POC mode)');
  return { json: input };
}

const HEYGEN_API_KEY = 'OWQxZDRjZmUxMmI4NDIzMDg2NjI3NTRmYWJlNTdmMTgtMTc1OTM0MjExNQ==';
const REPLICATE_API_KEY = '[REPLICATE_KEY_REDACTED]';
const RVM_VERSION = '73d2128a371922d5d1abf0712a1d974be0e4e2358cc1218e4e34714767232bac';

// Avatar ID comes from client config
const avatarId = input.avatar_id;
if (!avatarId) throw new Error('avatar_id required for HeyGen renders');

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function httpReq(opts) {
  return await this.helpers.httpRequest({ ...opts, json: true });
}

const updatedGroups = [];

for (const group of avatarGroups) {
  if (!group.audio_url) {
    console.log(group.group_id + ': No audio_url, skipping');
    updatedGroups.push(group);
    continue;
  }

  console.log(group.group_id + ': Starting HeyGen render (' + group.avatar_variant + ')');

  // ── Step 1: Submit HeyGen render ──
  const heygenResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.heygen.com/v2/video/generate',
    headers: {
      'x-api-key': HEYGEN_API_KEY,
      'accept': 'application/json',
      'content-type': 'application/json'
