          type: 'talking_photo',
          talking_photo_id: avatarId
        },
        voice: {
          type: 'audio',
          audio_url: group.audio_url
        }
      }],
      dimension: { width: 720, height: 1280 }
    },
    json: true
  });

  const videoId = heygenResponse.data?.video_id;
  if (!videoId) throw new Error(group.group_id + ': HeyGen did not return video_id');
  console.log(group.group_id + ': HeyGen video_id = ' + videoId);

  // ── Step 2: Poll HeyGen for completion ──
  let avatarVideoUrl = null;
  const MAX_POLLS = 60; // 5 minutes max (60 * 5s)

  for (let i = 0; i < MAX_POLLS; i++) {
    await sleep(5000);

    const status = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.heygen.com/v1/video_status.get?video_id=' + videoId,
