      break;
    } else if (state === 'failed') {
      throw new Error(group.group_id + ': HeyGen render failed: ' + JSON.stringify(status.data?.error));
    }
  }

  if (!avatarVideoUrl) throw new Error(group.group_id + ': HeyGen render timed out after ' + MAX_POLLS + ' polls');
  console.log(group.group_id + ': HeyGen complete: ' + avatarVideoUrl);

  // ── Step 3: Submit Replicate RVM for alpha mask ──
  const rvmResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.replicate.com/v1/predictions',
    headers: {
      'Authorization': 'Bearer ' + REPLICATE_API_KEY,
