    },
    body: {
      version: RVM_VERSION,
      input: {
        input_video: avatarVideoUrl,
        output_type: 'alpha-mask'
      }
    },
    json: true
  });

  const predictionId = rvmResponse.id;
  if (!predictionId) throw new Error(group.group_id + ': Replicate did not return prediction id');
  console.log(group.group_id + ': RVM prediction_id = ' + predictionId);

  // ── Step 4: Poll Replicate for completion ──
  let maskUrl = null;

  for (let i = 0; i < MAX_POLLS; i++) {
    await sleep(5000);

    const rvmStatus = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.replicate.com/v1/predictions/' + predictionId,
      headers: { 'Authorization': 'Bearer ' + REPLICATE_API_KEY },
      json: true
    });

    console.log(group.group_id + ': RVM poll ' + (i + 1) + ' - ' + rvmStatus.status);

    if (rvmStatus.status === 'succeeded') {
      maskUrl = rvmStatus.output;
      break;
    } else if (rvmStatus.status === 'failed') {
      throw new Error(group.group_id + ': RVM failed: ' + JSON.stringify(rvmStatus.error));
    }
  }

  if (!maskUrl) throw new Error(group.group_id + ': RVM timed out');
  console.log(group.group_id + ': RVM complete: ' + maskUrl);

  updatedGroups.push({
    ...group,
    avatar_video_url: avatarVideoUrl,
    avatar_mask_url: maskUrl
  });
}

console.log('All avatar renders complete. ' + updatedGroups.length + ' groups.');

return {
  json: {
    ...input,
    _avatar_groups: updatedGroups
  }
};

})();
